export function Original(currentTeam, i) {
  var teams = [];
  let message = "";
  let returnTeam = currentTeam;

  function modify(currentTeam) {
    let msg = "";
    let toModify = 0;
    let obj = teams.find((o, j) => {
      if (o.teamName === currentTeam.teamName) {
        toModify = j;
      }
    });
    let teamToModify = teams[toModify];
    msg = "Team member name should be unique.";

    if (currentTeam.m1 !== "") teamToModify.m1 = currentTeam.m1;
    if (currentTeam.m2 !== "") teamToModify.m2 = currentTeam.m2;
    if (currentTeam.m3 !== "") teamToModify.m3 = currentTeam.m3;
    if (identicalMembers(teamToModify)) {
      msg =
        "When modify, original team members remain for empty fields and team members should be different";
      return { team: teamToModify, msg: msg };
    } else {
      teams[toModify] = teamToModify;
      teams[toModify].deleted = false; //delete for a mutant
      msg = "You have successfully modified your team.";
    }
    return { team: teams[toModify], msg: msg };
  }

  function delTeamLogically(currentTeam) {
    let msg = "";
    let obj = teams.find((o, j) => {
      if (o.teamName === currentTeam.teamName) {
        teams[j].deleted = true;
        msg = "Team has been logically deleted";
      }
    });
    return msg;
  }

  function foundTeam(currentTeam) {
    for (let i = 0; i < teams.length; i++)
      if (teams[i].teamName === currentTeam.teamName) return teams[i];
    return { teamName: "", m1: "", m2: "", m3: "", deleted: false };
  }

  function teamIsNew(team) {
    let msg = "New team is successfully added.";
    let isNew = true;
    let teamArray = Object.values(team);
    if (teams.length > 0)
      teams.find((t) => {
        if (!t.deleted) {
          let tArray = Object.values(t);
          for (let i = 1; i <= 3; i++) {
            for (let j = 1; j <= 3; j++) {
              if (tArray[i] === teamArray[j]) {
                isNew = false;
                msg = "Team member name should be unique.";
              }
            }
          }
        }
      });

    return { new: isNew, message: msg };
  }

  function insertTeam(newTeam) {
    let delMessage = "";
    if (identicalMembers(newTeam)) {
      return "Team members should be different";
    } else if (missingMembers(newTeam))
      return "Three team members are required";
    let result = teamIsNew(newTeam);
    if (result.new) {
      delMessage = handleDeletedTeams(newTeam);
      teams.push(newTeam);
      return result.message + delMessage;
    } else return result.message + delMessage;
  }

  function handleDeletedTeams(team) {
    let delNum = -1;
    let message = "";
    let copyTeams = JSON.parse(JSON.stringify(teams));
    let findNum = 0;

    copyTeams.find((t, j) => {
      if (
        t.deleted &&
        (t.m1 === team.m1 ||
          t.m1 === team.m2 ||
          t.m1 === team.m3 ||
          t.m2 === team.m1 ||
          t.m2 === team.m2 ||
          t.m2 === team.m3 ||
          t.m3 === team.m1 ||
          t.m3 === team.m2 ||
          t.m3 === team.m3)
      ) {
        delNum = j - findNum;
        message = message + " Team " + t.teamName + " is deleted.";
        teams.splice(delNum, 1);
        findNum++;
      }
    });
    return message;
  }

  function identicalMembers(team) {
    if (team.m1 === team.m2 || team.m1 === team.m3 || team.m2 === team.m3)
      return true;
    else return false;
  }

  function missingMembers(team) {
    if (team.m1 === "" || team.m2 === "" || team.m3 === "") return true;
  }

  if (arrayTeams[i] !== undefined)
    teams = JSON.parse(JSON.stringify(arrayTeams[i]));
  if (foundTeam(currentTeam).teamName === "") {
    message = insertTeam(currentTeam);
  } else if (
    !currentTeam.deleted &&
    currentTeam.m1 === "" &&
    currentTeam.m2 === "" &&
    currentTeam.m3 === ""
  )
    message = delTeamLogically(currentTeam);
  else if (foundTeam(currentTeam).deleted) {
    let modResult = modify(currentTeam);
    returnTeam = modResult.team;
    message = modResult.msg;
  } else if (foundTeam(currentTeam).teamName !== "")
    message = "Team name should be unique!";
  arrayTeams[i] = JSON.parse(JSON.stringify(teams));

  return { resultMessage: message, team: returnTeam };
}

