import React, { useState, useRef } from "react";
import "./App.css";
import { array_of_mutants, Original, init } from "./mutants";

/*
    App.js template for test-design
    Please use this as the text sample. It has a back button set maching with the test design style, etc...
*/

/*
                
    Komponens(function/class)  ->  JSX elemek  -> React -> DOM(HTML)
                       A       render                          |
           state változás <-------------------esemény----------      

*/

function App() {
  var [eredmeny, setEredmeny] = useState("-");
  var [killedMutants, setKilledMutants] = useState("-");
  var [testCaseNumber, setNumber] = useState(0);
  var [killed, setKilled] = useState([]);
  //var [wrongTests, setWrongTests] = useState("");
  var [wrongTests] = useState([]);
  var [printWrongTests, setPrintWrongTests] = useState("");
  var [missing, setMissing] = useState("");
  var [result, setResult] = useState("");
  var [mutant] = useState([]);
  var [wrongSolution, setWrongSolution] = useState(false);
  var [msg, setMessage] = useState("");

  var xInput = useRef();
  var yInput = useRef();
  var zInput = useRef();
  var vInput = useRef();

  var actualTeam = { team: undefined, resultMessage: "", msg: "" };
  var mutantTeam;

  function tryAgain() {
    for (var i = 0; i < array_of_mutants.length; i++) {
      killed[i] = false;
      mutant[i] = "";
    }
    setResult("");
    setMissing("");
    setNumber(0);
    setEredmeny(0);
    setWrongSolution(false);
    setMessage("");
    xInput.current.value = "";
    yInput.current.value = "";
    zInput.current.value = "";
    vInput.current.value = "";
    wrongTests[0] = "";
    init();
  }

  function callFunctions() {
    var team = {
      teamName: xInput.current.value,
      m1: yInput.current.value,
      m2: zInput.current.value,
      m3: vInput.current.value,
      deleted: false,
    };
    //var y = yInput.current.value;
    //var z = zInput.current.value;
    //var v = vInput.current.value;
    //   var totalPrice = 0;
    // var mutantHikers;
    var killedMutants1 = "";
    actualTeam = Original(team, 0);

    yInput.current.value = actualTeam.team.m1;
    zInput.current.value = actualTeam.team.m2;
    vInput.current.value = actualTeam.team.m3;

    setEredmeny(actualTeam.resultMessage);
    var superfluousTest = true;
    if (
      !(
        team.teamName === "" &&
        team.m1 === "" &&
        team.m2 === "" &&
        team.m3 === ""
      )
    ) {
      testCaseNumber++;
      for (var i = 0; i < array_of_mutants.length; i++) {
        if (!killed[i]) {
          mutantTeam = array_of_mutants[i](team, i + 1);
          mutant[i] = mutantTeam.mutant;
          if (actualTeam.resultMessage !== mutantTeam.resultMessage) {
            var j = i + 1;
            killedMutants1 = killedMutants1 + j + " ";
            killed[i] = true;
            //       superfluousTest = false;
          }
        }
      }
      /*
      if (superfluousTest) {
        wrongTests[0] =
          "This test case is superfluous as it will not find any BVA-reated bug that haven't been found by your previous tests!";
        wrongSolution = true;
        console.log(" wrongSolution " + wrongSolution);
        //     console.log(wrongTests[0], ' superfluous')
      } else wrongTests[0] = "";
      */
    }
    setWrongSolution(wrongSolution);
    setKilledMutants(killedMutants1);
    setNumber(testCaseNumber);
    setMessage(actualTeam.resultMessage);
  }

  function printResult() {
    var optimalTestCaseNumber = 1; //!!!!!!!!!!!!!!!!!!!!!!!!!!!!!!
    var missingTests = false;
    var missedTestNumber = 0;
    missing = "";

    //callFunctions()
    for (var i = 0; i < array_of_mutants.length; i++) {
      if (!killed[i]) {
        missing = "Your tests would fail for this bug: " + mutant[i];
        missingTests = true;
        missedTestNumber++;
        console.log("not killed new ", i);
      }
    }
    var ratio =
      100 - Math.round((missedTestNumber / array_of_mutants.length) * 100);
    printWrongTests = wrongTests;
    setPrintWrongTests(printWrongTests);
    console.log("wrong " + wrongSolution);
    if (testCaseNumber === 0) {
      result = "Please write your test cases!";
    } else if (
      !missingTests &&
      !wrongSolution &&
      testCaseNumber > optimalTestCaseNumber
    ) {
      result = "Congratulation, you are very good at test design! "; //Our solution requires xx test cases.
      //   } else if (!missingTests && testCaseNumber === optimalTestCaseNumber) {
    } else if (!missingTests && !wrongSolution) {
      result = "Congratulation, you are very good at test design!";
    } else
      result =
        "You have found " + ratio + "% of the potential bugs. Try again! ";
    setResult(result);
    setMissing(missing);
  }

  function printResultAndInit() {
    printResult();
    //clearData()
  }

  return (
    <div className="App">
      <header className="Back-header">
        <p class="Back">
          <a href="https://test-design.org/practical-exercises/">
            Back to Test Design Exercises
          </a>
        </p>
      </header>

      <header className="App-header">
        <p class="exercise">
          {" "}
          Read the specification below carefully. Add the test cases one by one.
          A test case ends with 'Next test'. You can continue adding test cases
          after 'Show my result'. <br />
          'Try again' starts a new test design session. &nbsp;&nbsp;You can use
          the <a href="https://cloud.harmony.ac/">Harmony tool</a> to make
          action-state test design and execute tests automatedly.
        </p>

        <p class="specification">
          <div style={{ textAlign: "center", fontSize: 20 }}>
            <b> Tour competition </b>
          </div>
          A tour competition application has three main operations: register,
          delete and restore. The rules are as follows: <br />
          <b>R1</b> Teams of exactly three people can register for a tour
          competition. <br />
          <b>R2</b> During the registration a unique team name and three unique
          team members should be entered. The registration happens when ‘Next
          team’ or ‘Add this test case’ is pressed. <br />
          <b>R3</b> A team can be logically deleted by entering the team name
          and leaving all three team members empty. <br />
          <b>R4</b> Logically deleted teams can be restored when inserting the
          deleted team name and fill at least one member name. For the empty
          fields, the team members remain unchanged. <br />
          Example: team name: Myteam, member 1: Hannah, member 2: Joe, member 3:
          Emma. Delete Myteam logically. Then inserting Myteam and filling
          member 2 with Joe, the original team will be restored. Filling member
          2 with Jean, the members of the modified team will be Hannah, Jean,
          and Emma. <br />
          <b>R5</b> A new team can involve a team member from a logically
          deleted team. In this case, the logically deleted team will be
          permanently deleted. <br />
          <b>R6</b> The application informs the user about the successful
          registration or deletion, otherwise displays an error message about
          the cause.
        </p>

        <p class="testcases">
          <span data-harmony-id="Missing test"> {missing}</span> <br />
          <span data-harmony-id="result">{result}</span> <br /> <br />
          Team: <input size="8" data-harmony-id="Team" ref={xInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;Member 1:{" "}
          <input size="4" data-harmony-id="Member1" ref={yInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;Member 2:{" "}
          <input size="4" data-harmony-id="Member2" ref={zInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;Member 3:{" "}
          <input size="4" data-harmony-id="Member3" ref={vInput} />
          &nbsp;&nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Next member"
            onClick={callFunctions}
          >
            {" "}
            Next team{" "}
          </button>{" "}
          <span
            data-harmony-id="Test case number"
            style={{ color: "mediumaquamarine" }}
          >
            Number of test cases: {testCaseNumber}
          </span>{" "}
          <br />
          {msg} <br />
          <button
            class="button"
            data-harmony-id="Add test"
            onClick={callFunctions}
          >
            {" "}
            Add this test case{" "}
          </button>
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button
            class="button"
            data-harmony-id="Stop"
            onClick={printResultAndInit}
          >
            {" "}
            Show my result{" "}
          </button>{" "}
          &nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;&nbsp;
          <button class="button" data-harmony-id="Try again" onClick={tryAgain}>
            {" "}
            Try again{" "}
          </button>{" "}
          <br />
        </p>
      </header>
    </div>
  );
}

export default App;
